     2→/**
     3→ * md-tldr CLI - Token-efficient markdown analysis
     4→ */
     5→
     6→import { Command, Options } from "@effect/cli";
     7→import { NodeContext, NodeRuntime } from "@effect/platform-node";
     8→import { Console, Effect, Option } from "effect";
     9→import * as fs from "node:fs/promises";
    10→import * as path from "node:path";
    11→
    12→import { parseFile } from "../parser/parser.js";
    13→import { buildIndex, getOutgoingLinks, getIncomingLinks } from "../index/indexer.js";
    14→import { watchDirectory } from "../index/watcher.js";
    15→import { search, getContext, formatContextForLLM } from "../search/searcher.js";
    16→import { buildEmbeddings, semanticSearch, getEmbeddingStats } from "../embeddings/semantic-search.js";
    17→import type { MdSection } from "../core/types.js";
    18→
    19→// ============================================================================
    20→// Helper Functions
    21→// ============================================================================
    22→
    23→const formatJson = (obj: unknown, pretty: boolean): string => {
    24→  return pretty ? JSON.stringify(obj, null, 2) : JSON.stringify(obj);
    25→};
    26→
    27→const printSection = (section: MdSection, indent: number = 0): string => {
    28→  const prefix = "  ".repeat(indent);
    29→  const bullet = section.level === 1 ? "#" : "-";
    30→  let output = `${prefix}${bullet} ${section.heading} (${section.metadata.tokenCount} tokens)\n`;
    31→
    32→  for (const child of section.children) {
    33→    output += printSection(child, indent + 1);
    34→  }
    35→
    36→  return output;
    37→};
    38→
    39→const isMarkdownFile = (filename: string): boolean => {
    40→  return filename.endsWith(".md") || filename.endsWith(".mdx");
    41→};
    42→
    43→const walkDir = async (dir: string): Promise<string[]> => {
    44→  const files: string[] = [];
    45→  const entries = await fs.readdir(dir, { withFileTypes: true });
    46→
    47→  for (const entry of entries) {
    48→    const fullPath = path.join(dir, entry.name);
    49→
    50→    // Skip hidden directories and node_modules
    51→    if (entry.name.startsWith(".") || entry.name === "node_modules") {
    52→      continue;
    53→    }
    54→
    55→    if (entry.isDirectory()) {
    56→      const subFiles = await walkDir(fullPath);
    57→      files.push(...subFiles);
    58→    } else if (entry.isFile() && isMarkdownFile(entry.name)) {
    59→      files.push(fullPath);
    60→    }
    61→  }
    62→
    63→  return files;
    64→};
    65→
    66→// ============================================================================
    67→// Command Options
    68→// ============================================================================
    69→
    70→const jsonOption = Options.boolean("json").pipe(
    71→  Options.withDescription("Output as JSON"),
    72→  Options.withDefault(false)
    73→);
    74→
    75→const prettyOption = Options.boolean("pretty").pipe(
    76→  Options.withDescription("Pretty-print JSON output"),
    77→  Options.withDefault(true)
    78→);
    79→
    80→// ============================================================================
    81→// Parse Command
    82→// ============================================================================
    83→
    84→const parseCommand = Command.make(
    85→  "parse",
    86→  {
    87→    file: Options.file("file").pipe(Options.withAlias("f")),
    88→    json: jsonOption,
    89→    pretty: prettyOption,
    90→  },
    91→  ({ file, json, pretty }) =>
    92→    Effect.gen(function* () {
    93→      const result = yield* parseFile(file).pipe(
    94→        Effect.mapError((e) => new Error(`${e._tag}: ${e.message}`))
    95→      );
    96→
    97→      if (json) {
    98→        yield* Console.log(formatJson(result, pretty));
    99→      } else {
   100→        yield* Console.log(`Document: ${result.title}`);
   101→        yield* Console.log(`Path: ${result.path}`);
   102→        yield* Console.log(`Tokens: ${result.metadata.tokenCount}`);
   103→        yield* Console.log(`Sections: ${result.metadata.headingCount}`);
   104→        yield* Console.log(`Links: ${result.metadata.linkCount}`);
   105→        yield* Console.log(`Code Blocks: ${result.metadata.codeBlockCount}`);
   106→        yield* Console.log("");
   107→        yield* Console.log("Structure:");
   108→        for (const section of result.sections) {
   109→          yield* Console.log(printSection(section));
   110→        }
   111→      }
   112→    })
   113→);
   114→
   115→// ============================================================================
   116→// Tree Command
   117→// ============================================================================
   118→
   119→const treeCommand = Command.make(
   120→  "tree",
   121→  {
   122→    dir: Options.directory("dir").pipe(
   123→      Options.withAlias("d"),
   124→      Options.withDefault(".")
   125→    ),
   126→    json: jsonOption,
   127→    pretty: prettyOption,
   128→  },
   129→  ({ dir, json, pretty }) =>
   130→    Effect.gen(function* () {
   131→      const resolvedDir = path.resolve(dir);
   132→
   133→      const files = yield* Effect.promise(() => walkDir(resolvedDir));
   134→
   135→      const tree: { path: string; relativePath: string }[] = files
   136→        .sort()
   137→        .map((f) => ({
   138→          path: f,
   139→          relativePath: path.relative(resolvedDir, f),
   140→        }));
   141→
   142→      if (json) {
   143→        yield* Console.log(formatJson(tree, pretty));
   144→      } else {
   145→        yield* Console.log(`Markdown files in ${resolvedDir}:`);
   146→        yield* Console.log("");
   147→        for (const file of tree) {
   148→          yield* Console.log(`  ${file.relativePath}`);
   149→        }
   150→        yield* Console.log("");
   151→        yield* Console.log(`Total: ${tree.length} files`);
   152→      }
   153→    })
   154→);
   155→
   156→// ============================================================================
   157→// Structure Command
   158→// ============================================================================
   159→
   160→const structureCommand = Command.make(
   161→  "structure",
   162→  {
   163→    file: Options.file("file").pipe(Options.withAlias("f")),
   164→    json: jsonOption,
   165→    pretty: prettyOption,
   166→  },
   167→  ({ file, json, pretty }) =>
   168→    Effect.gen(function* () {
   169→      const result = yield* parseFile(file).pipe(
   170→        Effect.mapError((e) => new Error(`${e._tag}: ${e.message}`))
   171→      );
   172→
   173→      const extractStructure = (
   174→        section: MdSection
   175→      ): { heading: string; level: number; tokens: number; children: unknown[] } => ({
   176→        heading: section.heading,
   177→        level: section.level,
   178→        tokens: section.metadata.tokenCount,
   179→        children: section.children.map(extractStructure),
   180→      });
   181→
   182→      const structure = {
   183→        title: result.title,
   184→        path: result.path,
   185→        totalTokens: result.metadata.tokenCount,
   186→        sections: result.sections.map(extractStructure),
   187→      };
   188→
   189→      if (json) {
   190→        yield* Console.log(formatJson(structure, pretty));
   191→      } else {
   192→        yield* Console.log(`# ${result.title}`);
   193→        yield* Console.log(`Total tokens: ${result.metadata.tokenCount}`);
   194→        yield* Console.log("");
   195→
   196→        const printOutline = (section: MdSection, depth: number = 0): Effect.Effect<void> =>
   197→          Effect.gen(function* () {
   198→            const indent = "  ".repeat(depth);
   199→            const marker = "#".repeat(section.level);
   200→            yield* Console.log(
   201→              `${indent}${marker} ${section.heading} [${section.metadata.tokenCount} tokens]`
   202→            );
   203→            for (const child of section.children) {
   204→              yield* printOutline(child, depth + 1);
   205→            }
   206→          });
   207→
   208→        for (const section of result.sections) {
   209→          yield* printOutline(section);
   210→        }
   211→      }
   212→    })
   213→);
   214→
   215→// ============================================================================
   216→// Index Command
   217→// ============================================================================
   218→
   219→const forceOption = Options.boolean("force").pipe(
   220→  Options.withDescription("Force full rebuild, ignoring cache"),
   221→  Options.withDefault(false)
   222→);
   223→
   224→const watchOption = Options.boolean("watch").pipe(
   225→  Options.withAlias("w"),
   226→  Options.withDescription("Watch for changes and re-index automatically"),
   227→  Options.withDefault(false)
   228→);
   229→
   230→const indexCommand = Command.make(
   231→  "index",
   232→  {
   233→    dir: Options.directory("dir").pipe(
   234→      Options.withAlias("d"),
   235→      Options.withDefault(".")
   236→    ),
   237→    force: forceOption,
   238→    watch: watchOption,
   239→    json: jsonOption,
   240→    pretty: prettyOption,
   241→  },
   242→  ({ dir, force, watch: watchMode, json, pretty }) =>
   243→    Effect.gen(function* () {
   244→      const resolvedDir = path.resolve(dir);
   245→
   246→      if (watchMode) {
   247→        yield* Console.log(`Watching ${resolvedDir} for changes...`);
   248→        yield* Console.log("Press Ctrl+C to stop.");
   249→        yield* Console.log("");
   250→
   251→        const watcher = yield* watchDirectory(resolvedDir, {
   252→          force,
   253→          onIndex: (result) => {
   254→            if (json) {
   255→              console.log(formatJson(result, pretty));
   256→            } else {
   257→              console.log(`Re-indexed ${result.documentsIndexed} documents (${result.duration}ms)`);
   258→            }
   259→          },
   260→          onError: (error) => {
   261→            console.error(`Watch error: ${error.message}`);
   262→          },
   263→        });
   264→
   265→        // Keep the process running until Ctrl+C
   266→        yield* Effect.async<never, never>(() => {
   267→          process.on("SIGINT", () => {
   268→            watcher.stop();
   269→            console.log("\nStopped watching.");
   270→            process.exit(0);
   271→          });
   272→        });
   273→      } else {
   274→        yield* Console.log(`Indexing ${resolvedDir}...`);
   275→
   276→        const result = yield* buildIndex(resolvedDir, { force });
   277→
   278→        if (json) {
   279→          yield* Console.log(formatJson(result, pretty));
   280→        } else {
   281→          yield* Console.log("");
   282→          yield* Console.log(`Indexed ${result.documentsIndexed} documents`);
   283→          yield* Console.log(`  Sections: ${result.sectionsIndexed}`);
   284→          yield* Console.log(`  Links: ${result.linksIndexed}`);
   285→          yield* Console.log(`  Duration: ${result.duration}ms`);
   286→
   287→          if (result.errors.length > 0) {
   288→            yield* Console.log("");
   289→            yield* Console.log(`Errors (${result.errors.length}):`);
   290→            for (const error of result.errors) {
   291→              yield* Console.log(`  ${error.path}: ${error.message}`);
   292→            }
   293→          }
   294→        }
   295→      }
   296→    })
   297→);
   298→
   299→// ============================================================================
   300→// Links Command
   301→// ============================================================================
   302→
   303→const linksCommand = Command.make(
   304→  "links",
   305→  {
   306→    file: Options.file("file").pipe(Options.withAlias("f")),
   307→    root: Options.directory("root").pipe(
   308→      Options.withAlias("r"),
   309→      Options.withDefault(".")
   310→    ),
   311→    json: jsonOption,
   312→    pretty: prettyOption,
   313→  },
   314→  ({ file, root, json, pretty }) =>
   315→    Effect.gen(function* () {
   316→      const resolvedRoot = path.resolve(root);
   317→      const resolvedFile = path.resolve(file);
   318→      const relativePath = path.relative(resolvedRoot, resolvedFile);
   319→
   320→      const links = yield* getOutgoingLinks(resolvedRoot, resolvedFile);
   321→
   322→      if (json) {
   323→        yield* Console.log(formatJson({ file: relativePath, links }, pretty));
   324→      } else {
   325→        yield* Console.log(`Outgoing links from ${relativePath}:`);
   326→        yield* Console.log("");
   327→        if (links.length === 0) {
   328→          yield* Console.log("  (none)");
   329→        } else {
   330→          for (const link of links) {
   331→            yield* Console.log(`  -> ${link}`);
   332→          }
   333→        }
   334→        yield* Console.log("");
   335→        yield* Console.log(`Total: ${links.length} links`);
   336→      }
   337→    })
   338→);
   339→
   340→// ============================================================================
   341→// Backlinks Command
   342→// ============================================================================
   343→
   344→const backlinksCommand = Command.make(
   345→  "backlinks",
   346→  {
   347→    file: Options.file("file").pipe(Options.withAlias("f")),
   348→    root: Options.directory("root").pipe(
   349→      Options.withAlias("r"),
   350→      Options.withDefault(".")
   351→    ),
   352→    json: jsonOption,
   353→    pretty: prettyOption,
   354→  },
   355→  ({ file, root, json, pretty }) =>
   356→    Effect.gen(function* () {
   357→      const resolvedRoot = path.resolve(root);
   358→      const resolvedFile = path.resolve(file);
   359→      const relativePath = path.relative(resolvedRoot, resolvedFile);
   360→
   361→      const links = yield* getIncomingLinks(resolvedRoot, resolvedFile);
   362→
   363→      if (json) {
   364→        yield* Console.log(formatJson({ file: relativePath, backlinks: links }, pretty));
   365→      } else {
   366→        yield* Console.log(`Incoming links to ${relativePath}:`);
   367→        yield* Console.log("");
   368→        if (links.length === 0) {
   369→          yield* Console.log("  (none)");
   370→        } else {
   371→          for (const link of links) {
   372→            yield* Console.log(`  <- ${link}`);
   373→          }
   374→        }
   375→        yield* Console.log("");
   376→        yield* Console.log(`Total: ${links.length} backlinks`);
   377→      }
   378→    })
   379→);
   380→
   381→// ============================================================================
   382→// Search Command
   383→// ============================================================================
   384→
   385→const headingOption = Options.text("heading").pipe(
   386→  Options.withAlias("h"),
   387→  Options.withDescription("Filter by heading pattern (regex)"),
   388→  Options.optional
   389→);
   390→
   391→const pathOption = Options.text("path").pipe(
   392→  Options.withAlias("p"),
   393→  Options.withDescription("Filter by file path pattern (glob-like)"),
   394→  Options.optional
   395→);
   396→
   397→const hasCodeOption = Options.boolean("has-code").pipe(
   398→  Options.withDescription("Only sections with code blocks"),
   399→  Options.withDefault(false)
   400→);
   401→
   402→const hasListOption = Options.boolean("has-list").pipe(
   403→  Options.withDescription("Only sections with lists"),
   404→  Options.withDefault(false)
   405→);
   406→
   407→const hasTableOption = Options.boolean("has-table").pipe(
   408→  Options.withDescription("Only sections with tables"),
   409→  Options.withDefault(false)
   410→);
   411→
   412→const limitOption = Options.integer("limit").pipe(
   413→  Options.withAlias("l"),
   414→  Options.withDescription("Maximum number of results"),
   415→  Options.withDefault(100)
   416→);
   417→
   418→const searchCommand = Command.make(
   419→  "search",
   420→  {
   421→    root: Options.directory("root").pipe(
   422→      Options.withAlias("r"),
   423→      Options.withDefault(".")
   424→    ),
   425→    heading: headingOption,
   426→    pathPattern: pathOption,
   427→    hasCode: hasCodeOption,
   428→    hasList: hasListOption,
   429→    hasTable: hasTableOption,
   430→    limit: limitOption,
   431→    json: jsonOption,
   432→    pretty: prettyOption,
   433→  },
   434→  ({ root, heading, pathPattern, hasCode, hasList, hasTable, limit, json, pretty }) =>
   435→    Effect.gen(function* () {
   436→      const resolvedRoot = path.resolve(root);
   437→
   438→      // Build search options - only include filters that are actively set
   439→      const searchOptions: Parameters<typeof search>[1] = {
   440→        heading: Option.getOrUndefined(heading),
   441→        pathPattern: Option.getOrUndefined(pathPattern),
   442→        hasCode: hasCode ? true : undefined,
   443→        hasList: hasList ? true : undefined,
   444→        hasTable: hasTable ? true : undefined,
   445→        limit,
   446→      };
   447→
   448→      const results = yield* search(resolvedRoot, searchOptions);
   449→
   450→      if (json) {
   451→        const output = results.map((r) => ({
   452→          path: r.section.documentPath,
   453→          heading: r.section.heading,
   454→          level: r.section.level,
   455→          tokens: r.section.tokenCount,
   456→          line: r.section.startLine,
   457→          hasCode: r.section.hasCode,
   458→          hasList: r.section.hasList,
   459→          hasTable: r.section.hasTable,
   460→        }));
   461→        yield* Console.log(formatJson(output, pretty));
   462→      } else {
   463→        yield* Console.log(`Search results (${results.length}):`);
   464→        yield* Console.log("");
   465→
   466→        for (const result of results) {
   467→          const levelMarker = "#".repeat(result.section.level);
   468→          const meta: string[] = [];
   469→          if (result.section.hasCode) meta.push("code");
   470→          if (result.section.hasList) meta.push("list");
   471→          if (result.section.hasTable) meta.push("table");
   472→          const metaStr = meta.length > 0 ? ` [${meta.join(", ")}]` : "";
   473→
   474→          yield* Console.log(
   475→            `  ${result.section.documentPath}:${result.section.startLine}`
   476→          );
   477→          yield* Console.log(
   478→            `    ${levelMarker} ${result.section.heading}${metaStr} (${result.section.tokenCount} tokens)`
   479→          );
   480→          yield* Console.log("");
   481→        }
   482→      }
   483→    })
   484→);
   485→
   486→// ============================================================================
   487→// Context Command
   488→// ============================================================================
   489→
   490→const tokensOption = Options.integer("tokens").pipe(
   491→  Options.withAlias("t"),
   492→  Options.withDescription("Maximum tokens to include"),
   493→  Options.optional
   494→);
   495→
   496→const levelOption = Options.choice("level", ["brief", "summary", "full"]).pipe(
   497→  Options.withDescription("Compression level"),
   498→  Options.withDefault("summary" as const)
   499→);
   500→
   501→const contextCommand = Command.make(
   502→  "context",
   503→  {
   504→    file: Options.file("file").pipe(Options.withAlias("f")),
   505→    root: Options.directory("root").pipe(
   506→      Options.withAlias("r"),
   507→      Options.withDefault(".")
   508→    ),
   509→    tokens: tokensOption,
   510→    level: levelOption,
   511→    json: jsonOption,
   512→    pretty: prettyOption,
   513→  },
   514→  ({ file, root, tokens, level, json, pretty }) =>
   515→    Effect.gen(function* () {
   516→      const resolvedRoot = path.resolve(root);
   517→      const maxTokens = Option.getOrUndefined(tokens);
   518→
   519→      const context = yield* getContext(resolvedRoot, file, {
   520→        maxTokens,
   521→        level: level as "brief" | "summary" | "full",
   522→        includeContent: level === "full",
   523→      });
   524→
   525→      if (json) {
   526→        yield* Console.log(formatJson(context, pretty));
   527→      } else {
   528→        yield* Console.log(formatContextForLLM(context));
   529→      }
   530→    })
   531→);
   532→
   533→// ============================================================================
   534→// Embed Command
   535→// ============================================================================
   536→
   537→const embedCommand = Command.make(
   538→  "embed",
   539→  {
   540→    root: Options.directory("root").pipe(
   541→      Options.withAlias("r"),
   542→      Options.withDefault(".")
   543→    ),
   544→    force: forceOption,
   545→    json: jsonOption,
   546→    pretty: prettyOption,
   547→  },
   548→  ({ root, force, json, pretty }) =>
   549→    Effect.gen(function* () {
   550→      const resolvedRoot = path.resolve(root);
   551→
   552→      yield* Console.log(`Building embeddings for ${resolvedRoot}...`);
   553→
   554→      const result = yield* buildEmbeddings(resolvedRoot, { force });
   555→
   556→      if (json) {
   557→        yield* Console.log(formatJson(result, pretty));
   558→      } else {
   559→        yield* Console.log("");
   560→        yield* Console.log(`Embedded ${result.sectionsEmbedded} sections`);
   561→        yield* Console.log(`  Tokens used: ${result.tokensUsed}`);
   562→        yield* Console.log(`  Cost: $${result.cost.toFixed(6)}`);
   563→        yield* Console.log(`  Duration: ${result.duration}ms`);
   564→      }
   565→    })
   566→);
   567→
   568→// ============================================================================
   569→// Semantic Search Command
   570→// ============================================================================
   571→
   572→const queryArg = Options.text("query").pipe(
   573→  Options.withAlias("q"),
   574→  Options.withDescription("Natural language query for semantic search")
   575→);
   576→
   577→const thresholdOption = Options.float("threshold").pipe(
   578→  Options.withDescription("Minimum similarity threshold (0-1)"),
   579→  Options.withDefault(0.5)
   580→);
   581→
   582→const semanticCommand = Command.make(
   583→  "semantic",
   584→  {
   585→    query: queryArg,
   586→    root: Options.directory("root").pipe(
   587→      Options.withAlias("r"),
   588→      Options.withDefault(".")
   589→    ),
   590→    limit: limitOption,
   591→    threshold: thresholdOption,
   592→    pathPattern: pathOption,
   593→    json: jsonOption,
   594→    pretty: prettyOption,
   595→  },
   596→  ({ query, root, limit, threshold, pathPattern, json, pretty }) =>
   597→    Effect.gen(function* () {
   598→      const resolvedRoot = path.resolve(root);
   599→
   600→      const results = yield* semanticSearch(resolvedRoot, query, {
   601→        limit,
   602→        threshold,
   603→        pathPattern: Option.getOrUndefined(pathPattern),
   604→      });
   605→
   606→      if (json) {
   607→        yield* Console.log(formatJson(results, pretty));
   608→      } else {
   609→        yield* Console.log(`Semantic search results for: "${query}"`);
   610→        yield* Console.log(`Results: ${results.length}`);
   611→        yield* Console.log("");
   612→
   613→        for (const result of results) {
   614→          const similarity = (result.similarity * 100).toFixed(1);
   615→          yield* Console.log(`  ${result.documentPath}`);
   616→          yield* Console.log(`    ${result.heading} (${similarity}% match)`);
   617→          yield* Console.log("");
   618→        }
   619→      }
   620→    })
   621→);
   622→
   623→// ============================================================================
   624→// Embedding Stats Command
   625→// ============================================================================
   626→
   627→const statsCommand = Command.make(
   628→  "stats",
   629→  {
   630→    root: Options.directory("root").pipe(
   631→      Options.withAlias("r"),
   632→      Options.withDefault(".")
   633→    ),
   634→    json: jsonOption,
   635→    pretty: prettyOption,
   636→  },
   637→  ({ root, json, pretty }) =>
   638→    Effect.gen(function* () {
   639→      const resolvedRoot = path.resolve(root);
   640→      const stats = yield* getEmbeddingStats(resolvedRoot);
   641→
   642→      if (json) {
   643→        yield* Console.log(formatJson(stats, pretty));
   644→      } else {
   645→        yield* Console.log("Embedding stats:");
   646→        yield* Console.log("");
   647→        if (stats.hasEmbeddings) {
   648→          yield* Console.log(`  Vectors: ${stats.count}`);
   649→          yield* Console.log(`  Provider: ${stats.provider}`);
   650→          yield* Console.log(`  Dimensions: ${stats.dimensions}`);
   651→          yield* Console.log(`  Total tokens: ${stats.totalTokens}`);
   652→          yield* Console.log(`  Total cost: $${stats.totalCost.toFixed(6)}`);
   653→        } else {
   654→          yield* Console.log("  No embeddings found.");
   655→          yield* Console.log("  Run 'mdtldr embed' to build embeddings.");
   656→        }
   657→      }
   658→    })
   659→);
   660→
   661→// ============================================================================
   662→// Main CLI
   663→// ============================================================================
   664→
   665→const mainCommand = Command.make("mdtldr").pipe(
   666→  Command.withDescription("Token-efficient markdown analysis tool for LLMs"),
   667→  Command.withSubcommands([
   668→    parseCommand,
   669→    treeCommand,
   670→    structureCommand,
   671→    indexCommand,
   672→    linksCommand,
   673→    backlinksCommand,
   674→    searchCommand,
   675→    contextCommand,
   676→    embedCommand,
   677→    semanticCommand,
   678→    statsCommand,
   679→  ])
   680→);
   681→
   682→const cli = Command.run(mainCommand, {
   683→  name: "mdtldr",
   684→  version: "0.1.0",
   685→});
   686→
   687→// Run
   688→Effect.suspend(() => cli(process.argv)).pipe(
   689→  Effect.provide(NodeContext.layer),
   690→  NodeRuntime.runMain
   691→);
   692→

